namespace ArchStudy.FeatureBased;

public static class FeatureBasedModule
{
    public static IServiceCollection AddFeatureBasedModule(this IServiceCollection services)
    {
        services.AddDbContext<FeatureBasedDbContext>(o => o.UseSqlite("Data Source=archstudy-feature-based.db"));

        services.AddScoped<IAccountsRepository, AccountsRepository>();
        services.AddScoped<IAccountsService, AccountsService>();
        services.AddScoped<IDepositsRepository, DepositsRepository>();
        services.AddScoped<IDepositsService, DepositsService>();
        services.AddScoped<IWithdrawalsRepository, WithdrawalsRepository>();
        services.AddScoped<IWithdrawalsService, WithdrawalsService>();
        services.AddScoped<ITransfersRepository, TransfersRepository>();
        services.AddScoped<ITransfersService, TransfersService>();
        services.AddScoped<IStatementsRepository, StatementsRepository>();
        services.AddScoped<IStatementsService, StatementsService>();
        return services;
    }

    public static IEndpointRouteBuilder MapFeatureBasedModule(this IEndpointRouteBuilder routes)
    {
        var group = routes.MapGroup("/feature-based").WithTags("Feature-Based");
        AccountsController.Map(group);
        DepositsController.Map(group);
        WithdrawalsController.Map(group);
        TransfersController.Map(group);
        StatementsController.Map(group);
        return routes;
    }

    public static async Task EnsureDatabaseCreatedAsync(IServiceProvider services)
    {
        var db = services.GetRequiredService<FeatureBasedDbContext>();
        await db.Database.EnsureCreatedAsync();
    }
}

using ArchStudy.Shared.Dtos;

namespace ArchStudy.FeatureBased.Features.Accounts;

public static class AccountsController
{
    public static void Map(RouteGroupBuilder group)
    {
        group.MapPost("/accounts", async Task<IResult> (CreateAccountRequest req, IAccountsService svc, CancellationToken ct) =>
        {
            var account = await svc.CreateAsync(req.Owner, ct);
            return Results.Created($"/feature-based/accounts/{account.Id}", account);
        });

        group.MapGet("/accounts/{id:guid}", async Task<IResult> (Guid id, IAccountsService svc, CancellationToken ct) =>
        {
            var account = await svc.GetAsync(id, ct);
            return account is null ? Results.NotFound() : Results.Ok(account);
        });
    }
}

using ArchStudy.FeatureBased.Shared;
using Microsoft.EntityFrameworkCore;

namespace ArchStudy.FeatureBased.Features.Accounts;

public interface IAccountsRepository
{
    Task<AccountRow?> FindAsync(Guid id, CancellationToken ct);
    Task AddAsync(AccountRow account, CancellationToken ct);
    Task SaveAsync(CancellationToken ct);
}

public class AccountsRepository(FeatureBasedDbContext db) : IAccountsRepository
{
    public Task<AccountRow?> FindAsync(Guid id, CancellationToken ct) =>
        db.Accounts.FirstOrDefaultAsync(a => a.Id == id, ct);

    public async Task AddAsync(AccountRow account, CancellationToken ct) =>
        await db.Accounts.AddAsync(account, ct);

    public Task SaveAsync(CancellationToken ct) => db.SaveChangesAsync(ct);
}

using ArchStudy.FeatureBased.Shared;
using ArchStudy.Shared.Dtos;

namespace ArchStudy.FeatureBased.Features.Accounts;

public interface IAccountsService
{
    Task<AccountResponse> CreateAsync(string owner, CancellationToken ct);
    Task<AccountResponse?> GetAsync(Guid id, CancellationToken ct);
}

public class AccountsService(IAccountsRepository repo) : IAccountsService
{
    public async Task<AccountResponse> CreateAsync(string owner, CancellationToken ct)
    {
        if (string.IsNullOrWhiteSpace(owner)) throw new ArgumentException("Owner required");
        var row = new AccountRow { Id = Guid.NewGuid(), Owner = owner, Balance = 0m, CreatedAt = DateTime.UtcNow };
        await repo.AddAsync(row, ct);
        await repo.SaveAsync(ct);
        return new AccountResponse(row.Id, row.Owner, row.Balance, row.CreatedAt);
    }

    public async Task<AccountResponse?> GetAsync(Guid id, CancellationToken ct)
    {
        var row = await repo.FindAsync(id, ct);
        return row is null ? null : new AccountResponse(row.Id, row.Owner, row.Balance, row.CreatedAt);
    }
}

